import os
from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch, ConnectionError, TransportError

# Initialize Flask app
app = Flask(__name__)

# Configuration for Elasticsearch
ELASTICSEARCH_HOST = os.environ.get('ELASTICSEARCH_HOST', 'localhost')
ELASTICSEARCH_PORT = int(os.environ.get('ELASTICSEARCH_PORT', 9200))
ELASTICSEARCH_INDEX = os.environ.get('ELASTICSEARCH_INDEX', 'products')
ELASTICSEARCH_SCHEME = os.environ.get('ELASTICSEARCH_SCHEME', 'http')
ELASTICSEARCH_API_KEY_ID = os.environ.get('ELASTICSEARCH_API_KEY_ID')
ELASTICSEARCH_API_KEY = os.environ.get('ELASTICSEARCH_API_KEY')
ELASTICSEARCH_CLOUD_ID = os.environ.get('ELASTICSEARCH_CLOUD_ID')
ELASTICSEARCH_USERNAME = os.environ.get('ELASTICSEARCH_USERNAME')
ELASTICSEARCH_PASSWORD = os.environ.get('ELASTICSEARCH_PASSWORD')


# Initialize Elasticsearch client
# Prioritize cloud ID, then API key, then username/password, then just host/port
if ELASTICSEARCH_CLOUD_ID:
    es = Elasticsearch(
        cloud_id=ELASTICSEARCH_CLOUD_ID,
        api_key=(ELASTICSEARCH_API_KEY_ID, ELASTICSEARCH_API_KEY) if ELASTICSEARCH_API_KEY_ID and ELASTICSEARCH_API_KEY else None,
        basic_auth=(ELASTICSEARCH_USERNAME, ELASTICSEARCH_PASSWORD) if ELASTICSEARCH_USERNAME and ELASTICSEARCH_PASSWORD else None
    )
elif ELASTICSEARCH_API_KEY_ID and ELASTICSEARCH_API_KEY:
    es = Elasticsearch(
        [f"{ELASTICSEARCH_SCHEME}://{ELASTICSEARCH_HOST}:{ELASTICSEARCH_PORT}"],
        api_key=(ELASTICSEARCH_API_KEY_ID, ELASTICSEARCH_API_KEY)
    )
elif ELASTICSEARCH_USERNAME and ELASTICSEARCH_PASSWORD:
    es = Elasticsearch(
        [f"{ELASTICSEARCH_SCHEME}://{ELASTICSEARCH_HOST}:{ELASTICSEARCH_PORT}"],
        basic_auth=(ELASTICSEARCH_USERNAME, ELASTICSEARCH_PASSWORD)
    )
else:
    es = Elasticsearch(
        [f"{ELASTICSEARCH_SCHEME}://{ELASTICSEARCH_HOST}:{ELASTICSEARCH_PORT}"]
    )

# Test Elasticsearch connection
try:
    if not es.ping():
        raise ConnectionError("Could not connect to Elasticsearch!")
    print("Successfully connected to Elasticsearch!")
except ConnectionError as e:
    print(f"Elasticsearch connection error: {e}")
    # Depending on your deployment, you might want to exit or handle gracefully
    # For now, we'll let the app run but search requests will fail.


@app.route('/api/search', methods=['GET'])
def search_products():
    """
    Searches for products in Elasticsearch based on a keyword.
    GET /api/search?q=keyword
    """
    query = request.args.get('q', '').strip()
    if not query:
        return jsonify({'error': 'Query parameter "q" is required'}), 400

    try:
        # Define the Elasticsearch search body
        # Using a multi_match query for broader search across multiple fields
        # 'fields' can be customized based on your product document structure
        # Boosting fields like 'name' can prioritize matches in product names
        search_body = {
            "query": {
                "multi_match": {
                    "query": query,
                    "fields": ["name^3", "description^1", "category^2", "tags"],
                    "type": "best_fields",  # or "most_fields", "cross_fields"
                    "fuzziness": "AUTO" # Add fuzziness for typo tolerance
                }
            },
            "size": 20,  # Limit the number of results, adjust as needed
            # You can add aggregations, highlighting, sorting here
            "highlight": {
                "fields": {
                    "name": {},
                    "description": {}
                }
            }
        }

        # Execute the search query
        response = es.search(index=ELASTICSEARCH_INDEX, body=search_body)

        hits = []
        for hit in response['hits']['hits']:
            # Extract relevant fields from the hit
            product = hit['_source']
            product['id'] = hit['_id'] # Add Elasticsearch document ID
            if 'highlight' in hit:
                product['highlight'] = hit['highlight'] # Add highlighting if available
            hits.append(product)

        return jsonify({
            'query': query,
            'total_results': response['hits']['total']['value'],
            'products': hits
        }), 200

    except ConnectionError:
        return jsonify({'error': 'Could not connect to Elasticsearch'}), 503
    except TransportError as e:
        # Log the detailed Elasticsearch error for debugging
        print(f"Elasticsearch TransportError: {e.status_code} - {e.info}")
        return jsonify({'error': 'Elasticsearch query failed', 'details': e.info}), e.status_code
    except Exception as e:
        # Catch any other unexpected errors
        print(f"An unexpected error occurred: {e}")
        return jsonify({'error': 'An internal server error occurred'}), 500


if __name__ == '__main__':
    # For production, consider using a WSGI server like Gunicorn
    # For development, you can run directly:
    # FLASK_APP=your_app_name.py flask run
    # or with python -m flask run
    app.run(host='0.0.0.0', port=5000, debug=True)